def test_bug001_simulate_small_runs_does_not_crash():
    """REQ-001: simulate muss fuer beliebige runs>=1 normiert zurueckkehren, nicht crashen."""
    from src.model import monte_carlo
    mc = monte_carlo.simulate(1.3, 1.3, runs=50, seed=1)
    # Probs sind auf 4 Nachkommastellen gerundet -> Toleranz entsprechend
    assert abs(sum(mc["probs"].values()) - 1.0) < 1e-3


def test_bug002_uncertainty_band_invariant_to_runs():
    """REQ-002: Bandbreite muss ~invariant gegen MC_RUNS sein (Parameter-Unsicherheit)."""
    from src.model import monte_carlo
    def width(r):
        b = monte_carlo.simulate(1.6, 1.0, runs=r, seed=1, rho=0.0)["uncertainty"]["team1_win"]
        return b["p95"] - b["p05"]
    w_lo, w_hi = width(20000), width(200000)
    assert abs(w_lo - w_hi) < 0.03, f"Band schrumpft mit runs: {w_lo:.4f} -> {w_hi:.4f}"


def test_bug003_blend_lambdas_uses_books_when_market_absent():
    """REQ-003: fehlt Polymarket, muss blend_lambdas die Buecher-Torstruktur nutzen (wie blend_probs)."""
    from src.model import ensemble
    books = {"probs": {"team1_win": 0.60, "draw": 0.25, "team2_win": 0.15}}
    model = {"probs": {"team1_win": 0.40, "draw": 0.30, "team2_win": 0.30},
             "lambda1": 1.30, "lambda2": 1.30}
    blend = ensemble.blend_probs(None, model, None, books=books)
    lams = ensemble.blend_lambdas(None, model, blend.get("weights_used", {}), books=books)
    # Buecher implizieren lam1>lam2; korrekte Mischung muss von der reinen Modell-1.30/1.30 abweichen
    assert abs(lams["lambda1"] - 1.30) > 0.02, f"lambda ignoriert Buecher: {lams}"


def test_bug004_integer_total_line_respects_push():
    """REQ-004: bei Linie 3.0 muss p_under = P(total<=2) sein, nicht 1 - P(total>=4)."""
    from src.model import monte_carlo, value_betting
    mc = monte_carlo.simulate(1.4, 1.2, runs=40000, seed=3)
    match = {"team1": "A", "team2": "B",
             "ensemble": {"probs": mc["probs"]}, "monte_carlo": mc, "model": {}}
    slot = {"best_odds": 2.0, "book": "bk", "consensus_prob": 0.5, "n_books": 10}
    best = {"h2h": {}, "n_bookmakers": 10, "books": ["bk"],
            "totals": {"3.0": {"over": dict(slot), "under": dict(slot)}}}
    out = value_betting.evaluate_match(match, best)
    under = next(r for r in out["rows"] if r["selection"].startswith("Under"))
    td = mc["total_goals_dist"]
    expected = round(sum(td[:3]), 4)  # P(total<=2)
    assert abs(under["p_model"] - expected) < 0.02, f"Push leakt: {under['p_model']} != {expected}"


def test_bug005_totals_sigma_not_smaller_than_1x2():
    """REQ-005: ein Markt ohne MC-Band darf bei gleichem Edge kein kleineres sigma bekommen."""
    from src.model import value_betting as vb
    r_1x2 = vb._row("1X2", "s", 3.0, "bk", 0.55, 0.50, band_width=0.18, n_books=20)
    r_tot = vb._row("Über/Unter", "s", 3.0, "bk", 0.55, 0.50, band_width=None, n_books=20)
    assert r_tot["sigma"] >= r_1x2["sigma"] - 1e-9, (r_tot["sigma"], r_1x2["sigma"])


def test_bug006_whale_exposure_is_usd_commensurable(monkeypatch):
    """REQ-006: Holder-Exposure muss in USD (amount*Preis) zaehlen, nicht roh als Anteilszahl."""
    from src.model import whale_scoring
    from src.data_sources import polymarket_client as pm
    monkeypatch.setattr(pm, "get_user_activity", lambda *a, **k: [])
    monkeypatch.setattr(whale_scoring.time, "sleep", lambda *a, **k: None)
    # Markt: Yes-Preis fuer team1_win = 0.50
    snap = {"market": {"raw": {"team1_win": 0.50, "draw": 0.30, "team2_win": 0.20},
                       "probs": {"team1_win": 0.5, "draw": 0.3, "team2_win": 0.2}},
            "holders": {"team1_win": [{"proxyWallet": "0xH", "amount": 800}]},
            "trades": {}}
    sig = whale_scoring.whale_signal(snap)
    expo = sig["wallets"][0]["exposure"]["team1_win"]
    # 800 Anteile @ 0.50 = $400 USD-Exposure (kommensurabel mit Trade-USD); Code zaehlt roh 800
    assert abs(expo - 400.0) < 1.0, f"Holder-Anteile nicht in USD bewertet: {expo}"


