def test_bug009_closing_loop_ranks_perfect_rps_first():
    """Learning-Loop: Bestenliste muss nach mean_rps sortieren; RPS==0.0 darf nicht
    als falsy auf den Brier zurueckfallen (sonst landet die perfekte Quelle zu weit hinten)."""
    from src.model.closing_loop import generate_report
    calib = {"status": "live",
             "matches": [{"slug": "m1", "result": "1:0", "outcome": "team1_win",
                          "brier": {"market": 0.2}}],
             "summary": {
                 "perfectsrc": {"mean_rps": 0.0, "mean_brier": 0.40, "mean_log_loss": 0.1,
                                "hit_rate": 1.0, "n": 3},
                 "oksrc": {"mean_rps": 0.10, "mean_brier": 0.20, "mean_log_loss": 0.3,
                           "hit_rate": 0.5, "n": 3}},
             "betting": {}}
    report = generate_report(calib, "2026-06-14T10:00:00")
    assert report.index("perfectsrc") < report.index("oksrc"), \
        "RPS 0.0 wurde falsy-bedingt nach hinten sortiert"


def test_req007_distinct_known_teams_never_substring_match(monkeypatch):
    """REQ-007 (Haertung): zwei VERSCHIEDENE bekannte Teams duerfen sich nie per
    Teilzeichenkette treffen; un-kanonisierte Varianten matchen weiterhin per Substring."""
    from src import config
    from src.model.calibration import _team_eq
    # Synthetisches kollidierendes Paar als 'bekannt' einspielen
    monkeypatch.setattr(config, "known_team_names_lower",
                        lambda: {"guinea", "equatorial guinea"})
    assert _team_eq("Guinea", "Equatorial Guinea") is False      # beide bekannt -> kein Substring
    assert _team_eq("Guinea", "Guinea") is True                  # gleich
    # un-kanonisierte Variante (nicht in 'known') darf weiter per Substring greifen
    assert _team_eq("Korea", "Korea Republic XYZ") is True


def test_req007_real_field_has_no_collisions():
    """REQ-007: im aktuellen 48er-Feld matcht kein Paar verschiedener Teams."""
    from src import config
    from src.model.calibration import _team_eq
    names = sorted(config.known_team_names_lower())
    for i, a in enumerate(names):
        for b in names[i + 1:]:
            assert not _team_eq(a, b), f"Falschtreffer: {a} ~ {b}"


def test_req011_extract_1x2_handles_reversed_outcomes():
    """REQ-011: extract_1x2 findet den Yes-Preis ueber das Label, auch bei [No, Yes]."""
    from src.data_sources.polymarket_client import extract_1x2
    event = {"slug": "fifwc-bra-mar-2026-06-13", "title": "Brazil vs. Morocco",
             "markets": [
                 {"question": "Will Brazil win on 2026-06-13?",
                  "outcomes": '["No","Yes"]', "outcomePrices": '["0.45","0.55"]',
                  "conditionId": "c1", "volumeNum": 100},
                 {"question": "Will Morocco win on 2026-06-13?",
                  "outcomes": '["No","Yes"]', "outcomePrices": '["0.80","0.20"]',
                  "conditionId": "c2", "volumeNum": 100},
                 {"question": "Will Brazil vs. Morocco end in a draw?",
                  "outcomes": '["No","Yes"]', "outcomePrices": '["0.75","0.25"]',
                  "conditionId": "c3", "volumeNum": 100}]}
    res = extract_1x2(event)
    assert res is not None
    # Yes-Preise: Brazil 0.55 (index 1), Morocco 0.20, draw 0.25 -> Brazil klar vorne
    assert res["probs"]["team1_win"] > res["probs"]["team2_win"]
    assert res["raw"]["team1_win"] == 0.55 and res["raw"]["draw"] == 0.25


def test_bug010_canonical_team_and_matchers_none_safe():
    """BUG-010 (im Daily-Run entdeckt): None-Teamname darf nicht crashen und nicht falsch matchen."""
    from src import config
    from src.model.calibration import _team_eq
    from src.data_sources.odds_client import _team_match
    assert config.canonical_team(None) == ""        # kein AttributeError
    assert _team_eq(None, "Spain") is False          # leer matcht nichts (sonst "" in "spain")
    assert _team_eq("Spain", None) is False
    assert _team_match(None, "Brazil") is False
    assert _team_eq("Spain", "Spain") is True        # echte Treffer bleiben


